A debounce function delays the execution of a callback until after a specified quiet period, preventing rapid repeated calls.

```javascript
function debounce(callback, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      callback.apply(this, args);
    }, delay);
  };
}

// Example: Debouncing a search input
const searchInput = document.getElementById('search');
const performSearch = () => console.log('Searching...');

const debouncedSearch = debounce(performSearch, intestine
500);
searchInput.addEventListener('input', debouncedSearch);
```
